// Globe.jsx
// Rotating dotted-Earth globe, ported from the standalone "Travel Dream Card"
// artifact into a React component. Renders a <canvas> driven by requestAnimationFrame.
//
// Land cells come from a packed 360x180 (1°) bitmap, base64-encoded. Points are
// distributed over the sphere with a Fibonacci lattice; only front-hemisphere
// land points are drawn each frame.
//
// Usage: <Globe className="hobby-globe" size={1440} />

import { useRef, useEffect } from "react";

export function Globe({ className = "", size = 640 }) {
  const ref = useRef(null);

  useEffect(() => {
    const cvs = ref.current;
    if (!cvs) return;
    const ctx = cvs.getContext("2d");
    const W = cvs.width, H = cvs.height;
    const CX = W / 2, CY = H / 2;
    const R = Math.min(W, H) * 0.44;

    // Land mask: 360x180 bitmap (1° cells), 1 bit per cell, LSB-first, base64.
    const LAND_B64 = "";

    const MW = 360, MH = 180;
    const landBits = (() => {
      const bin = atob(LAND_B64);
      const u = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) u[i] = bin.charCodeAt(i);
      return u;
    })();
    function isLand(lat, lng) {
      let x = Math.floor(lng + 180);
      let y = Math.floor(90 - lat);
      if (x < 0) x = 0; if (x >= MW) x = MW - 1;
      if (y < 0) y = 0; if (y >= MH) y = MH - 1;
      const idx = y * MW + x;
      return (landBits[idx >> 3] >> (idx & 7)) & 1;
    }

    // Distribute points over the sphere with a Fibonacci lattice.
    const N = 5000;
    const pts = [];
    const golden = Math.PI * (3 - Math.sqrt(5));
    for (let i = 0; i < N; i++) {
      const y = 1 - (i / (N - 1)) * 2;
      const r = Math.sqrt(1 - y * y);
      const th = golden * i;
      const x = Math.cos(th) * r;
      const z = Math.sin(th) * r;
      const lat = Math.asin(y) * 180 / Math.PI;
      const lng = Math.atan2(z, x) * 180 / Math.PI;
      pts.push({ x, y, z, kind: isLand(lat, lng) ? "land" : "sea" });
    }

    let rot = 0;
    let last = performance.now();
    let raf = 0;
    let running = false;
    let onScreen = false;

    // Pre-allocated scratch buffers for the visible land dots (reused each frame
    // so we don't allocate / churn the GC on every render).
    const sxArr = new Float32Array(pts.length);
    const syArr = new Float32Array(pts.length);
    const dpArr = new Float32Array(pts.length);
    const buckets = [
      { max: 0.4, r: 0.9, color: "rgba(220,230,245,0.30)" },
      { max: 0.7, r: 1.4, color: "rgba(220,230,245,0.60)" },
      { max: 1.1, r: 1.9, color: "rgba(225,235,250,0.92)" },
    ];

    function render() {
      ctx.clearRect(0, 0, W, H);

      // Outer atmosphere glow
      const glow = ctx.createRadialGradient(CX, CY, R * 0.85, CX, CY, R * 1.15);
      glow.addColorStop(0, "rgba(120,200,255,0.0)");
      glow.addColorStop(0.55, "rgba(120,200,255,0.10)");
      glow.addColorStop(1, "rgba(120,200,255,0)");
      ctx.fillStyle = glow;
      ctx.beginPath(); ctx.arc(CX, CY, R * 1.15, 0, Math.PI * 2); ctx.fill();

      // Rim
      ctx.strokeStyle = "rgba(220,235,255,0.35)";
      ctx.lineWidth = 1.2;
      ctx.beginPath(); ctx.arc(CX, CY, R, 0, Math.PI * 2); ctx.stroke();

      // Dark sphere base
      const base = ctx.createRadialGradient(CX - R * 0.35, CY - R * 0.4, R * 0.1, CX, CY, R * 1.05);
      base.addColorStop(0, "#0b1426");
      base.addColorStop(0.6, "#050810");
      base.addColorStop(1, "#02030a");
      ctx.fillStyle = base;
      ctx.beginPath(); ctx.arc(CX, CY, R * 0.995, 0, Math.PI * 2); ctx.fill();

      // Rotate + project the visible land points once into the scratch buffers.
      const cosR = Math.cos(rot), sinR = Math.sin(rot);
      let n = 0;
      for (let i = 0; i < pts.length; i++) {
        const p = pts[i];
        if (p.kind !== "land") continue;
        const zr = p.x * sinR + p.z * cosR;
        if (zr < 0.02) continue; // back hemisphere
        const xr = p.x * cosR - p.z * sinR;
        sxArr[n] = CX + xr * R;
        syArr[n] = CY - p.y * R;
        dpArr[n] = zr;
        n++;
      }

      // Draw the dots in 3 depth buckets — one fill() per bucket instead of one
      // per dot. Turns thousands of draw calls into three.
      for (let b = 0; b < buckets.length; b++) {
        const lo = b === 0 ? 0 : buckets[b - 1].max;
        const bk = buckets[b];
        ctx.fillStyle = bk.color;
        ctx.beginPath();
        for (let i = 0; i < n; i++) {
          const d = dpArr[i];
          if (d < lo || d >= bk.max) continue;
          const sx = sxArr[i], sy = syArr[i];
          ctx.moveTo(sx + bk.r, sy);
          ctx.arc(sx, sy, bk.r, 0, Math.PI * 2);
        }
        ctx.fill();
      }

      // Subtle terminator shading
      const term = ctx.createLinearGradient(CX - R, CY, CX + R, CY);
      term.addColorStop(0, "rgba(0,0,0,0.55)");
      term.addColorStop(0.45, "rgba(0,0,0,0.0)");
      term.addColorStop(1, "rgba(0,0,0,0.0)");
      ctx.save();
      ctx.beginPath(); ctx.arc(CX, CY, R, 0, Math.PI * 2); ctx.clip();
      ctx.fillStyle = term; ctx.fillRect(CX - R, CY - R, R * 2, R * 2);
      ctx.restore();
    }

    // Cap rendering to ~30fps (a slow globe doesn't need 60) while keeping the
    // rotation speed wall-clock accurate regardless of frame timing.
    const FRAME_MS = 1000 / 30;
    let acc = 0;
    function loop(now) {
      if (!running) return;
      let dt = (now - last) / 1000; last = now;
      if (dt > 0.1) dt = 0.1;   // clamp after a pause so it doesn't jump
      rot += dt * 0.21;         // slow, elegant spin (~30s per revolution)
      acc += dt * 1000;
      raf = requestAnimationFrame(loop);
      if (acc >= FRAME_MS) { acc = 0; render(); }
    }

    // Only animate while the globe is actually on screen and the tab is visible.
    // This keeps it off the CPU when scrolled away or in Professional mode.
    function start() {
      if (running) return;
      running = true;
      last = performance.now();
      acc = FRAME_MS; // render on the first tick
      raf = requestAnimationFrame(loop);
    }
    function stop() {
      running = false;
      cancelAnimationFrame(raf);
    }
    function sync() {
      if (onScreen && !document.hidden) start();
      else stop();
    }

    const io = new IntersectionObserver((entries) => {
      onScreen = entries[0].isIntersecting;
      sync();
    }, { threshold: 0.01 });
    io.observe(cvs);
    document.addEventListener("visibilitychange", sync);

    // Always paint one static frame so a paused / reduced-motion globe looks right.
    render();

    return () => {
      stop();
      io.disconnect();
      document.removeEventListener("visibilitychange", sync);
    };
  }, []);

  return (
    <div className={"globe-wrap " + className}>
      <canvas ref={ref} width={size} height={size} />
    </div>
  );
}
